sql:
SELECT COUNT(*) 
FROM villages 
WHERE irrigation_infrastructure = 1;

SELECT gp_id, COUNT(village_id) AS village_count
FROM villages
GROUP BY gp_id;

SELECT COUNT(*) 
FROM irrigation_infrastructure 
WHERE status = 'operational';

SELECT EXISTS (
    SELECT 1 FROM water_usage
) AS has_water_usage_data;

SELECT water_source, water_availability
FROM water_availability
WHERE water_availability > 50;

SELECT village_id, COUNT(availability_id) AS water_availability_count
FROM water_availability
GROUP BY village_id;

SELECT village_id, total_population, female_population
FROM villages
ORDER BY total_population DESC;

external_knowledge:
; The query assumes that the "latest" notification is the one with the most recent date; 
; The query considers "operational" irrigation infrastructure, which implies that only functional systems are of interest;
; The water availability and usage measurements are crucial for understanding the village's current state, indicating that these metrics are important for village management or planning.
